    let rem = slice.len() - full;
    if rem > 0 {
        let mut block = [0u8; 64];
        block[..rem].copy_from_slice(&slice[full..]);
        let live = (1u64 << rem) - 1;
        index_tape_block_dispatch(&block, live, &mut carries, base + full as u32, seps, ends);
    }
    carries[1]
